example.code:
def beep():
    return "ding"

print(beep())  # 调用后才执行函数体

def cube(n):
    return n * n * n

print(cube(2))  # 8

def show_only():
    print(7)    # 屏幕有 7，返回 None

def give_back():
    return 7

a = show_only()   # a 是 None
b = give_back()   # b 是 7

def welcome(who):
    return "hey " + who

print(welcome("Sam"))  # hey Sam
